        const clampedOffset = Math.max(halfWidth, Math.min(maxOffset, offset));
        const blocked = overlapsExisting(wall.id, clampedOffset, WINDOW_WIDTH, floor.doors, floor.windows);

        editorDispatch({
          type: 'UPDATE_TOOL_STATE',
          payload: {
            previewWallId: wall.id,
            previewOffset: clampedOffset,
            previewBlocked: blocked,
          },
        });
      } else {
        editorDispatch({
          type: 'UPDATE_TOOL_STATE',
          payload: { previewWallId: null, previewOffset: null, previewBlocked: false },
        });
      }
    },

    onMouseDown(modelPos, e, toolState) {
      if (e.button !== 0) return;
      if (!toolState.previewWallId || toolState.previewBlocked) return;

      const win = createWindow(toolState.previewWallId, toolState.previewOffset);
      dispatch({ type: 'WINDOW_ADD', floorId: activeFloorId, window: win });
    },

    onKeyDown(e, toolState) {
      if (e.key === 'Escape') {
        editorDispatch({ type: 'SET_TOOL', tool: 'select' });
      }
    },

    getCursor(toolState) {
      if (!toolState.previewWallId || toolState.previewBlocked) return 'not-allowed';
      return 'copy';
    },
  };
}

