  1→import { signedPolygonArea } from './polygon';
  2→import { nearestPointOnSegment } from './line';
  3→import { ENDPOINT_MERGE_TOLERANCE, MIN_ROOM_AREA } from '@/domain/defaults';
  4→
  5→/**
  6→ * Detect rooms from wall topology using planar graph face extraction.
  7→ * Returns array of { points: [{x,y}], area: number }.
  8→ */
  9→export function detectRooms(walls, mergeTolerance = ENDPOINT_MERGE_TOLERANCE) {
 10→  if (walls.length < 3) return [];
 11→
 12→  // Step A: Collect and merge endpoints
 13→  const rawPoints = [];
 14→  for (const wall of walls) {
 15→    rawPoints.push(wall.start, wall.end);
 16→  }
 17→
 18→  // Merge nearby points — O(n²), fine for apartment scale
 19→  const vertices = []; // [{x, y}]
 20→  const pointToVertex = new Map(); // index in rawPoints -> index in vertices
 21→
 22→  function findOrAddVertex(p) {
 23→    for (let i = 0; i < vertices.length; i++) {
 24→      const v = vertices[i];
 25→      const dx = v.x - p.x;
 26→      const dy = v.y - p.y;
 27→      if (dx * dx + dy * dy <= mergeTolerance * mergeTolerance) {
 28→        return i;
 29→      }
 30→    }
 31→    vertices.push({ x: p.x, y: p.y });
 32→    return vertices.length - 1;
 33→  }
 34→
 35→  // Build edges from walls
 36→  const edges = []; // [{from, to}] as vertex indices
 37→  for (const wall of walls) {
 38→    const fromIdx = findOrAddVertex(wall.start);
 39→    const toIdx = findOrAddVertex(wall.end);
 40→    if (fromIdx === toIdx) continue; // degenerate
 41→    edges.push({ from: fromIdx, to: toIdx });
 42→  }
 43→
 44→  // Step A2: Split edges at T-junctions
 45→  let edgesChanged = true;
 46→  while (edgesChanged) {
 47→    edgesChanged = false;
 48→    for (let ei = edges.length - 1; ei >= 0; ei--) {
 49→      const edge = edges[ei];
