  const vertices = []; // [{x, y}]
  const pointToVertex = new Map(); // index in rawPoints -> index in vertices

  function findOrAddVertex(p) {
    for (let i = 0; i < vertices.length; i++) {
      const v = vertices[i];
      const dx = v.x - p.x;
      const dy = v.y - p.y;
      if (dx * dx + dy * dy <= mergeTolerance * mergeTolerance) {
        return i;
      }
    }
    vertices.push({ x: p.x, y: p.y });
    return vertices.length - 1;
  }

  // Build edges from walls
  const edges = []; // [{from, to}] as vertex indices
  for (const wall of walls) {
    const fromIdx = findOrAddVertex(wall.start);
    const toIdx = findOrAddVertex(wall.end);
    if (fromIdx === toIdx) continue; // degenerate
    edges.push({ from: fromIdx, to: toIdx });
  }

  // Add column edges — connects wall endpoints that land on different corners
  for (const column of columns) {
    const corners = columnOutline(column);
    for (let i = 0; i < corners.length; i++) {
      const fromIdx = findOrAddVertex(corners[i]);
      const toIdx = findOrAddVertex(corners[(i + 1) % corners.length]);
      if (fromIdx === toIdx) continue;
      edges.push({ from: fromIdx, to: toIdx });
    }
  }

  // Step A2: Split edges at T-junctions
  let edgesChanged = true;
  while (edgesChanged) {
    edgesChanged = false;
    for (let ei = edges.length - 1; ei >= 0; ei--) {
      const edge = edges[ei];
      const a = vertices[edge.from];
      const b = vertices[edge.to];
      const splits = []; // {t, vertIdx}

      for (let vi = 0; vi < vertices.length; vi++) {
        if (vi === edge.from || vi === edge.to) continue;
        const v = vertices[vi];
        const { point, t } = nearestPointOnSegment(v, a, b);
        if (t <= 0 || t >= 1) continue;
        const dx = point.x - v.x;
        const dy = point.y - v.y;
        if (dx * dx + dy * dy <= mergeTolerance * mergeTolerance) {
          splits.push({ t, vertIdx: vi });
        }
      }

      if (splits.length === 0) continue;
      edgesChanged = true;
      splits.sort((a, b) => a.t - b.t);

      // Replace edge with N+1 sub-edges
      const subEdges = [];
      let prev = edge.from;
      for (const sp of splits) {
        subEdges.push({ from: prev, to: sp.vertIdx });
        prev = sp.vertIdx;
      }
      subEdges.push({ from: prev, to: edge.to });
      edges.splice(ei, 1, ...subEdges);
    }
